// PATTERN: Amazon Login
// TAGS: amazon, login, auth, signin, password
// DESCRIPTION: Robust Amazon login flow with bot detection handling, email entry, and password verification.

test('Amazon Login Verification', async ({ page }) => {
    // 1. Bot detection & Navigation
    await page.goto('https://www.amazon.com', { waitUntil: 'domcontentloaded' });
    const title = await page.title();
    if (title.includes('Robot Check')) throw new Error('BOT_DETECTED');

    // 2. Go to Sign In
    await page.locator('#nav-link-accountList').click();
    await page.waitForTimeout(2000);

    // 3. Enter Email
    const email = process.env.AMAZON_EMAIL;
    if (!email) throw new Error('AMAZON_EMAIL env var missing');

    await page.fill('input[type="email"]', email);

    // Improved Continue Button handling
    const continueBtn = page.locator('input#continue, input[type="submit"]').first();

    // Strategy 1: Enter Key (most reliable)
    await page.keyboard.press('Enter');

    // Strategy 2: Forced Click if still on email page
    try {
        await expect(page.locator('input[type="password"]')).toBeVisible({ timeout: 5000 });
    } catch (e) {
        console.log('Enter key failed, trying forced click on Continue button...');
        if (await continueBtn.isVisible()) {
            await continueBtn.click({ force: true });
        }
    }

    // Final Check: Race to see if we get Password field OR Invalid Email
    try {
        await Promise.race([
            page.locator('input[type="password"]').waitFor({ state: 'visible', timeout: 10000 }),
            page.locator('text=Looks like you\'re new to Amazon').waitFor({ state: 'visible', timeout: 10000 }),
            page.locator('text=Proceed to create an account').waitFor({ state: 'visible', timeout: 10000 }),
            page.locator('text=There was a problem').waitFor({ state: 'visible', timeout: 10000 })
        ]);
    } catch (e) {
        throw new Error('login failed due to invalid email');
    }

    // After race, check if we landed on an error page
    const isInvalid = await Promise.race([
        page.locator('text=Looks like you\'re new to Amazon').isVisible(),
        page.locator('text=Proceed to create an account').isVisible(),
        page.locator('text=There was a problem').isVisible()
    ]);

    if (isInvalid) {
        throw new Error('login failed due to invalid email');
    }

    // Verify password field is actually what we found
    if (!await page.locator('input[type="password"]').isVisible()) {
        throw new Error('login failed due to invalid email');
    }

    // 4. Handle Password & Verification
    const password = process.env.AMAZON_PASSWORD;
    if (!password) throw new Error('AMAZON_PASSWORD env var missing');

    await page.fill('input[type="password"]', password);
    const signInBtn = page.locator('#signInSubmit');
    await signInBtn.click();

    // 5. Verify Login Status
    try {
        await expect(page.locator('#nav-link-accountList-nav-line-1')).toContainText(/Hello,/, { timeout: 10000 });
        console.log('✅ Login Successful');
    } catch (e) {
        const errorMsg = await page.locator('.a-list-item').textContent().catch(() => '');
        if (errorMsg?.includes('password')) throw new Error('Login Failed: Invalid Password');
        throw new Error('Login Failed: Unknown Reason');
    }
});

